class Solution(object):
    def hasIncreasingSubarrays(self, nums, k):
        def is_inc(start):
            for i in range(start, start + k - 1):
                if nums[i] >= nums[i + 1]:
                    return False
            return True
        for a in range(len(nums) - 2 * k + 1):
            if is_inc(a) and is_inc(a + k):
                return True
        return False
